#include<bits/stdc++.h>
#define int long long
#define fst(a,b,c) for(int a=(b);a<=(c);a++)
using namespace std;
const int N=5e6+100,INF=5e18;
int n,nn,m,lst;
int a[N],cpy[N];
int Rt[N],cnt;
vector<int> loc[N];
struct node{int lmx,rmx,mx,sum,ls,rs;}t[N],MN,Emp;
int read()
{
	char in=getchar(); int x=0; bool tag=0;
	while(!isdigit(in)) tag=(in=='-'),in=getchar();
	while(isdigit(in)) x=x*10+(in^48),in=getchar();
	return tag?-x:x;
}
void up(int rt)
{
	t[rt].sum=t[t[rt].ls].sum+t[t[rt].rs].sum;
	t[rt].mx=t[rt].lmx=t[rt].rmx=-INF;
	if(t[rt].ls) t[rt].lmx=t[t[rt].ls].lmx,t[rt].mx=max(t[rt].mx,t[t[rt].ls].mx);
	if(t[rt].rs) t[rt].rmx=t[t[rt].rs].rmx,t[rt].mx=max(t[rt].mx,t[t[rt].rs].mx);
	if(t[rt].ls&&t[rt].rs)
	{
		t[rt].lmx=max(t[rt].lmx,t[t[rt].ls].sum+t[t[rt].rs].lmx);
		t[rt].rmx=max(t[rt].rmx,t[t[rt].rs].sum+t[t[rt].ls].rmx);
		t[rt].mx=max(t[rt].mx,t[t[rt].ls].rmx+t[t[rt].rs].lmx);
	}
}
int build(int L=0,int R=n+1)
{
	int rt=++cnt;
	if(L==R)
	{
		t[rt].sum=t[rt].lmx=t[rt].rmx=t[rt].mx=1;
		return rt;
	}
	int mid=(L+R)>>1;
	t[rt].ls=build(L,mid);
	t[rt].rs=build(mid+1,R);
	up(rt);
	return rt;
}
void upd(int k,int num,int &x,int rt,int L=0,int R=n+1)
{
	x=++cnt; t[x].sum=t[rt].sum; t[x].ls=t[rt].ls; t[x].rs=t[rt].rs;
	t[x].mx=t[rt].mx; t[x].lmx=t[rt].lmx; t[x].rmx=t[rt].rmx;
	if(L==R){
		t[x].sum=t[x].mx=t[x].lmx=t[x].rmx=num;
		return;
	}
	int mid=(L+R)>>1;
	(k<=mid)?upd(k,num,t[x].ls,t[rt].ls,L,mid):upd(k,num,t[x].rs,t[rt].rs,mid+1,R);
	up(x);
}
int qry_sum(int l,int r,int rt,int L=0,int R=n+1)
{
	if(!rt) return 0; if(l<=L&&R<=r) return t[rt].sum;
	int mid=(L+R)>>1;
	if(l<=mid&&r<=mid) return qry_sum(l,r,t[rt].ls,L,mid);
	else if(l>mid&&r>mid) return qry_sum(l,r,t[rt].rs,mid+1,R);
	else return qry_sum(l,r,t[rt].ls,L,mid)+qry_sum(l,r,t[rt].rs,mid+1,R);
}
node qry_mx(int l,int r,int rt,int L=0,int R=n+1)
{
	if(!rt) return Emp;
	if(l<=L&&R<=r) return t[rt];
	int mid=(L+R)>>1;
	if(l<=mid&&r<=mid) return qry_mx(l,r,t[rt].ls,L,mid);
	else if(l>mid&&r>mid) return qry_mx(l,r,t[rt].rs,mid+1,R);
	else
	{
		node Ls=qry_mx(l,r,t[rt].ls,L,mid),Rs=qry_mx(l,r,t[rt].rs,mid+1,R),ans=Emp;
		ans.sum=Ls.sum+Rs.sum;
		ans.mx=max(Ls.rmx+Rs.lmx,max(Ls.mx,Rs.mx));
		ans.lmx=max(Ls.lmx,Ls.sum+Rs.lmx);
		ans.rmx=max(Rs.rmx,Rs.sum+Ls.rmx);
		return ans;
	}
}
int opt[45645];
bool check(int x)
{
	int ans=0;
	if(opt[2]+1<=opt[3]-1) ans=qry_sum(opt[2]+1,opt[3]-1,Rt[x]);
	ans+=qry_mx(opt[1],opt[2],Rt[x]).rmx+qry_mx(opt[3],opt[4],Rt[x]).lmx;
	return ans>=0;
}
struct Sort
{
	int x,y;
	inline bool operator<(const Sort &Q)const{return x<Q.x;}
}Q[N];
void solve()
{
	int l,r,mid,ans=0;
	opt[1]=(read()+lst)%n+1,opt[2]=(read()+lst)%n+1;
	opt[3]=(read()+lst)%n+1,opt[4]=(read()+lst)%n+1;
	sort(opt+1,opt+5); l=1; r=n;
	while(l<=r){
		mid=(l+r)>>1;
		if(check(mid)) ans=mid,l=mid+1; 
		else r=mid-1;
	}
	printf("%lld\n",lst=Q[ans].x);
}

signed main()
{
	MN=(node){-INF,-INF,-INF,-INF,-INF,-INF};
	Emp=(node){0,0,0,0,0,0};
	n=nn=read();
	fst(i,1,n) a[i]=cpy[i]=Q[i].x=read(),Q[i].y=i;
	sort(Q+1,Q+n+1);sort(cpy+1,cpy+n+1);
	fst(i,1,n){
		loc[i].push_back(Q[i].y);
	}
	Rt[1]=build();
	fst(i,2,n)for(int v:loc[i-1])upd(v,-1,Rt[i],Rt[i-1]);
	m=read();
	while(m--) solve();
	return 0;
}
